-- Fixes NguoiSuDungThietBi audit fields from real equipment data.
SET NOCOUNT ON;
IF OBJECT_ID('tempdb..#NguoiDungAuditCu') IS NOT NULL DROP TABLE #NguoiDungAuditCu;
CREATE TABLE #NguoiDungAuditCu (MaNguoiDung NVARCHAR(50) NOT NULL PRIMARY KEY, LogUser NVARCHAR(50) NULL, LogDate DATETIME2 NULL, LogUserLast NVARCHAR(50) NULL, LogDateLast DATETIME2 NULL);

UPDATE nsd
SET
    nsd.NgayKhoiTao = COALESCE(a.LogDate, nsd.NgayKhoiTao),
    nsd.MaNguoiNhap = COALESCE(NULLIF(a.LogUser, N''), nsd.MaNguoiNhap),
    nsd.TenNguoiNhap = CASE
        WHEN NULLIF(a.LogUser, N'') IS NULL THEN nsd.TenNguoiNhap
        WHEN a.LogUser = N'0044' THEN N'Trương Văn Voôn'
        ELSE a.LogUser
    END,
    nsd.NgayChinhSuaCuoiCung = a.LogDateLast,
    nsd.MaNguoiChinhSua = NULLIF(a.LogUserLast, N''),
    nsd.TenNguoiChinhSua = CASE
        WHEN NULLIF(a.LogUserLast, N'') IS NULL THEN NULL
        WHEN a.LogUserLast = N'0044' THEN N'Trương Văn Voôn'
        ELSE a.LogUserLast
    END
FROM dbo.NguoiSuDungThietBi nsd
JOIN #NguoiDungAuditCu a ON a.MaNguoiDung = nsd.MaNguoiDung;

DROP TABLE #NguoiDungAuditCu;
GO
